import java.sql.*;

public class SecureSQLInjectionExample {

    public static void main(String[] args) {
        try {
            String userInput = "admin'; DROP TABLE users; --"; // This is a malicious input

            // Connect to the database
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a SQL statement with PreparedStatement to avoid SQL Injection
            String query = "SELECT * FROM users WHERE username = ?";
            PreparedStatement preparedStatement = connection.prepareStatement(query);

            // Set user input as parameter in the PreparedStatement
            preparedStatement.setString(1, userInput);

            // Execute the query using PreparedStatement
            ResultSet resultSet = preparedStatement.executeQuery();

            // Process the results
            while (resultSet.next()) {
                System.out.println(resultSet.getString("username"));
                System.out.println(resultSet.getString("password"));
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

